/// Math-symbol lookup (any face); None = not covered.
pub(crate) fn math_glyph(c: char) -> Option<&'static Glyph> {
    let i = match c as u32 {
        0x00B0 => 0, // '°' degree
        0x00B1 => 1, // '±' plus-minus
        0x00B7 | 0x22C5 => 2, // '·' middle dot / cdot
        0x00D7 => 3, // '×' times
        0x00F7 => 4, // '÷' divide
        0x2190 => 5, // '←' left arrow
        0x2191 => 6, // '↑' up arrow
        0x2192 => 7, // '→' right arrow
        0x2193 => 8, // '↓' down arrow
        0x2200 => 9, // '∀' for all
        0x2202 => 10, // '∂' partial
        0x2203 => 11, // '∃' exists
        0x2205 => 12, // '∅' empty set
        0x2207 => 13, // '∇' nabla
        0x2208 => 14, // '∈' element of
        0x220F => 15, // '∏' n-ary product
        0x2211 => 16, // '∑' n-ary summation
        0x2213 => 17, // '∓' minus-plus
        0x221A => 18, // '√' square root
        0x221D => 19, // '∝' proportional to
        0x221E => 20, // '∞' infinity
        0x2220 => 21, // '∠' angle
        0x2229 => 22, // '∩' intersection
        0x222A => 23, // '∪' union
        0x222B => 24, // '∫' integral
        0x223C => 25, // '∼' tilde operator
        0x2234 => 26, // '∴' therefore
        0x2248 => 27, // '≈' almost equal
        0x2260 => 28, // '≠' not equal
        0x2261 => 29, // '≡' identical to
        0x2264 => 30, // '≤' less-or-equal
        0x2265 => 31, // '≥' greater-or-equal
        0x2282 => 32, // '⊂' subset of
        0x2283 => 33, // '⊃' superset of
        0x22A5 => 34, // '⊥' perpendicular
        _ => return None,
    };
    Some(&MATH[i])
}
